import type { StateCreator } from 'zustand';
import { AirlineMilesState, AirlineMilesActions } from '../models';

export interface AirlineMilesSlice {
  airlineMiles: AirlineMilesState;
  airlineMilesActions: AirlineMilesActions;
}

const INITIAL_STATE: AirlineMilesState = {
  redirectURL: '',
  isLoading: false,
  isError: false,
  errorMessage: '',
};

export const createAirlineMilesSlice: StateCreator<
  AirlineMilesSlice,
  [],
  [],
  AirlineMilesSlice
> = (set) => ({
  airlineMiles: INITIAL_STATE,
  airlineMilesActions: {
    setLoading: (isLoading) =>
      set((state) => ({
        airlineMiles: { ...state.airlineMiles, isLoading, isError: false, errorMessage: '' },
      })),
    setRedirectURL: (redirectURL) =>
      set((state) => ({
        airlineMiles: { ...state.airlineMiles, redirectURL, isLoading: false, isError: false },
      })),
    setError: (errorMessage) =>
      set((state) => ({
        airlineMiles: { ...state.airlineMiles, errorMessage, isError: true, isLoading: false },
      })),
    clearError: () =>
      set((state) => ({
        airlineMiles: { ...state.airlineMiles, isError: false, errorMessage: '' },
      })),
    reset: () =>
      set({ airlineMiles: INITIAL_STATE }),
  },
});
```

