export interface PointsProduct {
  name: string;
  redemptionOrigin?: string;
  convertionFactor?: number;
  minRedemptionValue?: number;
  productCode?: string;
  campaingId?: string;
  conversionFactor?: number;
  icon?: string;
  code?: string;
  origin?: string;
  points?: number;
  action?: string | null;
  campaignId?: string | null;
}

export enum PointsProductsStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface PointsProductsState {
  products: PointsProduct[];
  status: PointsProductsStatus;
  error?: string;
}

export interface PointsProductsActions {
  setStatus: (status: PointsProductsStatus) => void;
  setProducts: (products: PointsProduct[]) => void;
  setError: (error?: string) => void;
  reset: () => void;
}

export interface PointsProductsApiResponse {
  dados: PointsProduct[];
  status: {
    codigoRetorno: number;
    mensagem: string;
  };
}

import { api } from '@semparar/mf-app-user';
import type { PointsProductsApiResponse } from '../models';
import { getParticipantIdFromToken } from '../utils/participantId';

class PointsProductsApi {
  async getProducts(): Promise<PointsProductsApiResponse> {
    const participantId = getParticipantIdFromToken();
    const response = await api.get<PointsProductsApiResponse>(
      `/fintech/v1/rewardProgram/productslist`,
      {
        headers: {
          participantId,
        },
      }
    );
    return response.data;
  }
}

export const pointsProductsApi = new PointsProductsApi();

import type { PointsProduct, PointsProductsApiResponse } from '../models';

export function mapPointsProductsResponse(
  response: PointsProductsApiResponse
): PointsProduct[] {
  if (!response?.dados || !Array.isArray(response.dados)) {
    return [];
  }
  return response.dados;
}

import { useRootStore } from '~/store';
import { pointsProductsApi } from '../api';
import { mapPointsProductsResponse } from '../repository';
import { PointsProductsStatus } from '../models';

function shouldFetchProducts(): boolean {
  const { pointsProducts } = useRootStore.getState();
  return pointsProducts.status !== PointsProductsStatus.LOADING;
}

export async function getPointsProducts(): Promise<void> {
  if (!shouldFetchProducts()) {
    return;
  }

  const { pointsProductsActions } = useRootStore.getState();

  try {
    pointsProductsActions.setStatus(PointsProductsStatus.LOADING);

    const response = await pointsProductsApi.getProducts();

    if (response?.status?.codigoRetorno === 0) {
      const products = mapPointsProductsResponse(response);
      pointsProductsActions.setProducts(products);
    } else {
      pointsProductsActions.setError(response?.status?.mensagem);
      pointsProductsActions.setStatus(PointsProductsStatus.ERROR);
    }
  } catch (error) {
    pointsProductsActions.setError('Erro ao carregar produtos');
    pointsProductsActions.setStatus(PointsProductsStatus.ERROR);
  }
}

import type { StateCreator } from 'zustand';
import type { PointsProductsActions, PointsProductsState } from '../models';
import { PointsProductsStatus } from '../models';

export type PointsProductsSlice = {
  pointsProducts: PointsProductsState;
  pointsProductsActions: PointsProductsActions;
};

const initialPointsProductsState: PointsProductsState = {
  products: [],
  status: PointsProductsStatus.IDLE,
  error: undefined,
};

export const createPointsProductsSlice: StateCreator<
  PointsProductsSlice,
  [],
  [],
  PointsProductsSlice
> = (set) => ({
  pointsProducts: initialPointsProductsState,

  pointsProductsActions: {
    setStatus: (status) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          status,
          ...(status === PointsProductsStatus.LOADING && {
            error: undefined,
          }),
        },
      })),

    setProducts: (products) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          products,
          status: PointsProductsStatus.SUCCESS,
          error: undefined,
        },
      })),

    setError: (error) =>
      set((state) => ({
        pointsProducts: {
          ...state.pointsProducts,
          error,
        },
      })),

    reset: () =>
      set({
        pointsProducts: initialPointsProductsState,
      }),
  },
});

